-- ─────────────────────────────────────────────────────────────────────────────
-- 004_exercise_seed.sql
-- Replaces the global exercise catalog with a large curated set (250+ exercises)
-- spanning all six categories with full metadata for the rebuilt Workout tracker.
-- User-created exercises (user_id is not null) are preserved.
-- ─────────────────────────────────────────────────────────────────────────────

delete from public.exercise_catalog where is_global = true;

insert into public.exercise_catalog
  (user_id, is_global, name, muscle_group, equipment, exercise_type, category,
   secondary_muscles, movement_pattern, difficulty, equipment_detail,
   instructions, tips, common_mistakes, is_compound)
